const items = $input.all();
const artigos = [];

function safeJsonParse(text) {
  // Remove marcadores de código markdown
  let cleaned = text
    .replace(/```json/gi, '')
    .replace(/```/g, '')
    .replace(/^json\s*/i, '')
    .trim();

  try {
    // Tentativa 1: Parse direto
    return JSON.parse(cleaned);
  } catch (firstError) {
    try {
      // Tentativa 2: Escapa caracteres especiais ANTES de parsear
      // Isso é crucial para strings com quebras de linha
      const fixed = cleaned
        .replace(/\\/g, '\\\\')      // Escapa barras invertidas
        .replace(/\n/g, '\\n')       // Escapa quebras de linha
        .replace(/\r/g, '\\r')       // Escapa carriage return
        .replace(/\t/g, '\\t')       // Escapa tabs
        .replace(/\f/g, '\\f')       // Escapa form feed
        .replace(/"/g, '\\"')        // Escapa aspas duplas
        .replace(/\\\\"/g, '\\"');   // Corrige escape duplo de aspas

      return JSON.parse(fixed);
    } catch (secondError) {
      // Tentativa 3: Usa regex mais robusto para extrair campos
      try {
        const tituloMatch = cleaned.match(/"titulo"\s*:\s*"([^"]+)"/);
        const palavrasMatch = cleaned.match(/"palavras"\s*:\s*(\d+)/);
        const resumoMatch = cleaned.match(/"resumo_executivo"\s*:\s*"([^"]+)"/);

        // Extrai artigo_completo (pode ter aspas escapadas dentro)
        const artigoMatch = cleaned.match(/"artigo_completo"\s*:\s*"([\s\S]*?)"\s*,\s*"fontes"/);

        // Extrai fontes (array)
        const fontesMatch = cleaned.match(/"fontes"\s*:\s*(\[[\s\S]*?\])/);

        return {
          titulo: tituloMatch ? tituloMatch[1] : 'Sem título',
          artigo_completo: artigoMatch ? artigoMatch[1].replace(/\\n/g, '\n').replace(/\\"/g, '"') : '',
          palavras: palavrasMatch ? parseInt(palavrasMatch[1]) : 0,
          resumo_executivo: resumoMatch ? resumoMatch[1] : '',
          fontes: fontesMatch ? JSON.parse(fontesMatch[1]) : []
        };
      } catch (thirdError) {
        // Se tudo falhar, lança erro com informações úteis
        throw new Error(`Parse falhou em todas tentativas. Erros: ${firstError.message} | ${secondError.message} | ${thirdError.message}`);
      }
    }
  }
}

function montarFontesMarkdown(fontes) {
  if (!fontes || !fontes.length) return '';
  return (
    '\n\n## Fontes e Referências\n\n' +
    fontes.map(f =>
      `- **${f.titulo}** – ${f.fonte_instituicao}\n  ${f.url}`
    ).join('\n\n')
  );
}

for (const item of items) {
  try {
    let raw = item.json.output || item.json.text || item.json;
    if (typeof raw === 'string') {
      raw = safeJsonParse(raw);
    }
    artigos.push(raw);
  } catch (error) {
    artigos.push({
      erro: true,
      mensagem: error.message,
      raw_output: item.json.output || item.json.text || item.json
    });
  }
}

if (!artigos.length) {
  throw new Error('Nenhum artigo válido retornado.');
}

const agora = new Date();
const dataHora = agora.toLocaleString('pt-BR');

return artigos.map((artigo, index) => {
  if (artigo.erro) {
    return { json: artigo };
  }

  const fontes = artigo.fontes || [];
  let artigoCompleto = artigo.artigo_completo || '';

  // Injeta fontes se não existirem no texto
  if (!artigoCompleto.includes('## Fontes e Referências')) {
    artigoCompleto += montarFontesMarkdown(fontes);
  }

  const palavras = artigo.palavras || artigoCompleto.split(/\s+/).length;

  return {
    json: {
      titulo: artigo.titulo || 'Sem título',
      artigo_completo: artigoCompleto,
      resumo_executivo: artigo.resumo_executivo || '',
      palavras,
      fontes,
      total_fontes: fontes.length,
      metadados: {
        criado_em: dataHora,
        artigo_numero: index + 1
      },
      qualidade: {
        tem_titulo: !!artigo.titulo,
        tem_artigo: !!artigoCompleto,
        fontes_ok: fontes.length >= 5,
        palavras_ok: palavras >= 2500,
        aprovado:
          !!artigo.titulo &&
          !!artigoCompleto &&
          fontes.length >= 5 &&
          palavras >= 2500
      }
    }
  };
});
